import{c as a,Q as s,j as t,m as n}from"./chunks/framework.BPKcPtvA.js";const u=JSON.parse('{"title":"Hosted Checkout — overview","description":"One-click pay links for issuers to sell to non-customer buyers.","frontmatter":{"title":"Hosted Checkout — overview","description":"One-click pay links for issuers to sell to non-customer buyers."},"headers":[],"relativePath":"checkout/overview.md","filePath":"checkout/overview.md","lastUpdated":1780172233000}'),o={name:"checkout/overview.md"};function i(r,e,l,p,c,h){return s(),t("div",null,[...e[0]||(e[0]=[n(`<h1 id="hosted-checkout" tabindex="-1">Hosted Checkout <a class="header-anchor" href="#hosted-checkout" aria-label="Permalink to &quot;Hosted Checkout&quot;">​</a></h1><div class="warning custom-block"><p class="custom-block-title">🚧 In development — not in the Testing Guide</p><p>Hosted Checkout is still being hardened and isn&#39;t part of the judge/user <a href="/guide/">Testing Guide</a>. These pages describe the intended design. To evaluate MuHaven&#39;s agentic flows today, use <a href="/havenbot/overview">HavenBot</a> or the <a href="/mcp/overview">MCP server</a> instead.</p></div><p><code>muhaven.app/pay</code> is MuHaven&#39;s <strong>hosted checkout</strong> surface. It lets an issuer mint a one-off pay link, share it (Telegram, email, Twitter DM), and have a non-customer buyer pay with a passkey — no MuHaven account required ahead of time.</p><p>It&#39;s the only surface designed for <strong>users who don&#39;t yet have a MuHaven wallet</strong>. The first-time buyer&#39;s MuHaven wallet is provisioned via <code>@zerodev/passkey-validator</code> at checkout; returning buyers reuse it.</p><h2 id="the-link" tabindex="-1">The link <a class="header-anchor" href="#the-link" aria-label="Permalink to &quot;The link&quot;">​</a></h2><p>A checkout URL looks like:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>https://muhaven.app/pay/c/01HMTV9X.../#k=AbCdEfGhIjKlMnOpQrStUvWxYz123456</span></span></code></pre></div><p>Two parts:</p><ul><li><strong>Path</strong> (<code>/pay/c/&lt;ulid&gt;/</code>) — the public session ID. The server uses this to look up the <em>ciphertext</em> of the session payload.</li><li><strong>Fragment</strong> (<code>#k=...</code>) — the 32-byte AES-256-GCM decryption key. Encoded as base64url.</li></ul><p>The <strong>fragment is never sent in <code>Referer</code> headers</strong>, so the server holds ciphertext that&#39;s useless without the key. This is the <a href="https://stripe.com/docs/payments/checkout" target="_blank" rel="noreferrer">Stripe Checkout pattern</a> adapted for a privacy-preserving flow. See <a href="/checkout/fragment-key">URL fragment key (privacy)</a> for the full security argument.</p><h2 id="what-s-in-a-checkout-session" tabindex="-1">What&#39;s in a checkout session <a class="header-anchor" href="#what-s-in-a-checkout-session" aria-label="Permalink to &quot;What&#39;s in a checkout session&quot;">​</a></h2><p>The encrypted payload contains:</p><ul><li>Issuer label (&quot;You are paying [Issuer Verified]&quot; — Stripe pattern).</li><li>Token symbol and address.</li><li>Amount (in mhUSDC, 6-decimal).</li><li>Webhook URL (if the issuer wants real-time notifications).</li><li>TTL (default 30 minutes from creation).</li></ul><p>The buyer-facing page renders this in cleartext after the fragment-key decrypts the payload <strong>client-side</strong>.</p><h2 id="when-to-use-hosted-checkout" tabindex="-1">When to use Hosted Checkout <a class="header-anchor" href="#when-to-use-hosted-checkout" aria-label="Permalink to &quot;When to use Hosted Checkout&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Question</th><th>If yes → Hosted Checkout</th></tr></thead><tbody><tr><td>Are you an issuer minting a one-off pay link?</td><td>✅</td></tr><tr><td>Does your buyer not have a MuHaven account yet?</td><td>✅</td></tr><tr><td>Do you need a real-time settlement notification?</td><td>✅ (webhooks + SSE)</td></tr><tr><td>Do you need recurring billing?</td><td>❌ Not supported — each checkout is one-shot.</td></tr><tr><td>Do you want the buyer&#39;s strategy + identity to stay private from MuHaven&#39;s operators?</td><td>✅ (fragment-key keeps payload opaque to operator)</td></tr><tr><td>Do you want to drive checkout from an LLM workflow?</td><td>✅ — HavenBot&#39;s <code>create_checkout</code> tool mints the URL</td></tr></tbody></table><h2 id="end-to-end-flow" tabindex="-1">End-to-end flow <a class="header-anchor" href="#end-to-end-flow" aria-label="Permalink to &quot;End-to-end flow&quot;">​</a></h2><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>┌─ Issuer ──────────────────────────────────────────────────┐</span></span>
<span class="line"><span>│ 1. Calls HavenBot &quot;Create a checkout for 500 mhUSDC of    │</span></span>
<span class="line"><span>│    &lt;TOKEN&gt; expiring in 24 hours&quot;                           │</span></span>
<span class="line"><span>│ 2. HavenBot returns: https://muhaven.app/pay/c/.../#k=... │</span></span>
<span class="line"><span>│ 3. Issuer shares the link (Telegram / email / DM)         │</span></span>
<span class="line"><span>└────────────────────────────────────────────────────────────┘</span></span>
<span class="line"><span>                            │</span></span>
<span class="line"><span>                            │ shares</span></span>
<span class="line"><span>                            ▼</span></span>
<span class="line"><span>┌─ Buyer ───────────────────────────────────────────────────┐</span></span>
<span class="line"><span>│ 4. Opens the link in any modern browser                   │</span></span>
<span class="line"><span>│ 5. /pay page decrypts the payload with the fragment key   │</span></span>
<span class="line"><span>│    client-side; renders &quot;You are paying [Issuer Verified] │</span></span>
<span class="line"><span>│    500 mhUSDC of &lt;TOKEN&gt;&quot;                                  │</span></span>
<span class="line"><span>│ 6a. (First-time) Buyer creates a passkey at checkout      │</span></span>
<span class="line"><span>│     → MuHaven wallet deploys                              │</span></span>
<span class="line"><span>│ 6b. (Returning) Buyer signs in with existing passkey      │</span></span>
<span class="line"><span>│ 7. Buyer confirms; passkey signs the buy UserOp           │</span></span>
<span class="line"><span>│ 8. SSE channel streams settlement progress                │</span></span>
<span class="line"><span>│ 9. Buyer sees &quot;Settled&quot; + Arbiscan link                   │</span></span>
<span class="line"><span>└────────────────────────────────────────────────────────────┘</span></span>
<span class="line"><span>                            │</span></span>
<span class="line"><span>                            │ SSE / webhook</span></span>
<span class="line"><span>                            ▼</span></span>
<span class="line"><span>┌─ Issuer ──────────────────────────────────────────────────┐</span></span>
<span class="line"><span>│ 10. HavenBot says &quot;✅ checkout chk_01HMTV... paid&quot;         │</span></span>
<span class="line"><span>│ 11. (Optional) Webhook fires to issuer&#39;s URL              │</span></span>
<span class="line"><span>└────────────────────────────────────────────────────────────┘</span></span></code></pre></div><h2 id="what-s-available" tabindex="-1">What&#39;s available <a class="header-anchor" href="#what-s-available" aria-label="Permalink to &quot;What&#39;s available&quot;">​</a></h2><ul><li>Backend <code>checkout_sessions</code> table + REST routes under <code>/api/v1/checkout/*</code>.</li><li>AES-256-GCM enc_payload with key in URL fragment.</li><li>Stripe-style <code>MuHaven-Signature: t=,v1=</code> HMAC-SHA256 webhook signing with 5-min replay window.</li><li>In-process SSE channel with terminal-state auto-close + 25s heartbeat.</li><li>SSRF guard on outbound webhook URLs (blocks RFC1918 + 169.254 + IPv6 ULA + link-local).</li><li>Pluggable <code>FundingProvider</code> abstraction in <code>apps/checkout-pay/</code> Vite project — <code>FaucetRedirectProvider</code> for testnet; provider slots for on-ramp services on production.</li><li>Passkey ceremony for first-time buyers (RP-ID pinned to <code>muhaven.app</code>) via the ZeroDev-powered MuHaven wallet.</li></ul><h2 id="where-next" tabindex="-1">Where next <a class="header-anchor" href="#where-next" aria-label="Permalink to &quot;Where next&quot;">​</a></h2><div class="mh-card-grid"><a class="mh-card" href="/checkout/for-issuers"><h3>For issuers</h3><p>Create a checkout link via HavenBot. Webhook setup. Real-time monitoring.</p></a><a class="mh-card" href="/checkout/for-buyers"><h3>For buyers</h3><p>What the buyer sees, the passkey ceremony, the SSE settlement channel.</p></a><a class="mh-card" href="/checkout/fragment-key"><h3>URL fragment key</h3><p>Why the key lives in the URL fragment and what that protects against.</p></a><a class="mh-card" href="/checkout/webhooks"><h3>Webhooks &amp; receipts</h3><p>Signed webhooks, replay window, idempotency, SSRF guard.</p></a></div>`,22)])])}const k=a(o,[["render",i]]);export{u as __pageData,k as default};
